<fieldset disabled="@_isValidating">
    <legend>Shipping Information</legend>

    <div class="form-group">
        <label for="name">Name</label>
        <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" @bind="Shipping.Address" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" @bind="Shipping.City" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" @bind="Shipping.ZipCode" @bind:event="oninput" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_validationError))
{
    <div class="validation-error" role="alert">@_validationError</div>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        @: Validating…
    }
    else
    {
        @: Next
    }
</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private bool _isValidating;
    private string? _validationError;

    // Linked to _disposalCts so both user-retries and disposal cancel the pending call.
    private CancellationTokenSource? _validationCts;
    private readonly CancellationTokenSource _disposalCts = new();

    private async Task ValidateAndProceed()
    {
        // Cancel any in-flight validation from a previous click.
        _validationCts?.Cancel();
        _validationCts?.Dispose();
        _validationCts = CancellationTokenSource.CreateLinkedTokenSource(_disposalCts.Token);

        _validationError = null;
        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address,
                Shipping.City,
                Shipping.ZipCode,
                _validationCts.Token);

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check your inputs.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — either the user retried or the component was disposed.
        }
        catch (Exception)
        {
            _validationError = "An error occurred while validating the address. Please try again.";
        }
        finally
        {
            _isValidating = false;
        }
    }

    public void Dispose()
    {
        _disposalCts.Cancel();
        _disposalCts.Dispose();
        _validationCts?.Cancel();
        _validationCts?.Dispose();
    }
}

